```python
import math
import numpy as np

class LanguageModel:
    def __init__(self):
        self.word_counts = {}

    def train(self, text):
        words = text.split()
        for word in words:
            if word not in self.word_counts:
                self.word_counts[word] = 0
            self.word_counts[word] += 1

    def calculate_probability(self, word):
        if word not in self.word_counts:
            return 0
        total_words = sum(self.word_counts.values())
        return self.word_counts[word] / total_words

    def perplexity(self, text):
        words = text.split()
        probabilities = [self.calculate_probability(word) for word in words]
        log_likelihoods = [math.log(p) for p in probabilities]
        average_log_likelihood = np.mean(log_likelihoods)
